import { useState, useCallback } from 'react';
import { motion } from 'framer-motion';
import ShpeHatAnimation from './ShpeHatAnimation';

const SHPE_RED = '#C8102E';
const SHPE_BLUE = '#003087';

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.18, delayChildren: 0.1 },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 30 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.6, ease: 'easeOut' } },
};

export default function Home() {
  const [introDone, setIntroDone] = useState(false);
  const [fadeOut, setFadeOut] = useState(false);

  const handleComplete = useCallback(() => {
    setFadeOut(true);
    setTimeout(() => setIntroDone(true), 800);
  }, []);

  return (
    <main className="flex flex-col items-center justify-center min-h-screen font-sans overflow-hidden">
      {!introDone && (
        <div
          style={{
            transition: 'opacity 0.8s ease',
            opacity: fadeOut ? 0 : 1,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
          }}
        >
          <ShpeHatAnimation onComplete={handleComplete} />
        </div>
      )}

      {introDone && (
        <motion.section
          className="relative flex flex-col items-center justify-center text-center px-6 py-24 w-full"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <motion.video
            variants={itemVariants}
            src={require('../assets/shpe_animated_video.mp4')}
            autoPlay
            muted
            playsInline
            style={{ width: 'min(700px, 90vw)', borderRadius: '12px' }}
          />
          {/* Background accent blobs */}
          <div
            aria-hidden="true"
            style={{
              position: 'absolute',
              top: '-120px',
              left: '-120px',
              width: '400px',
              height: '400px',
              borderRadius: '50%',
              background: `radial-gradient(circle, ${SHPE_RED}22 0%, transparent 70%)`,
              filter: 'blur(40px)',
              pointerEvents: 'none',
            }}
          />
          <div
            aria-hidden="true"
            style={{
              position: 'absolute',
              bottom: '-120px',
              right: '-120px',
              width: '400px',
              height: '400px',
              borderRadius: '50%',
              background: `radial-gradient(circle, ${SHPE_BLUE}22 0%, transparent 70%)`,
              filter: 'blur(40px)',
              pointerEvents: 'none',
            }}
          />

          {/* Bienvenido */}
          <motion.p
            variants={itemVariants}
            className="text-lg tracking-widest uppercase font-semibold mb-2"
            style={{ color: SHPE_RED, letterSpacing: '0.25em' }}
          >
            Bienvenido a
          </motion.p>

          {/* SHPE */}
          <motion.h1
            variants={itemVariants}
            className="font-extrabold leading-none"
            style={{
              fontSize: 'clamp(5rem, 15vw, 11rem)',
              background: `linear-gradient(135deg, ${SHPE_RED} 0%, ${SHPE_BLUE} 100%)`,
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              backgroundClip: 'text',
            }}
          >
            SHPE
          </motion.h1>

          {/* Divider */}
          <motion.div
            variants={itemVariants}
            style={{
              width: '80px',
              height: '4px',
              borderRadius: '2px',
              background: `linear-gradient(90deg, ${SHPE_RED}, ${SHPE_BLUE})`,
              margin: '1rem auto',
            }}
          />

          {/* Full name */}
          <motion.h2
            variants={itemVariants}
            className="text-2xl sm:text-3xl font-bold tracking-tight"
            style={{ color: SHPE_BLUE }}
          >
            Society of Hispanic Professional Engineers
          </motion.h2>

          {/* Chapter */}
          <motion.p
            variants={itemVariants}
            className="text-xl sm:text-2xl font-semibold mt-1"
            style={{ color: SHPE_RED }}
          >
            Austin Chapter
          </motion.p>
        </motion.section>
      )}
    </main>
  );
}
